class Solution:
    def thirdMax(self, nums: List[int]) -> int:
        a = b = c = -10**18
        for x in nums:
            if x == a or x == b or x == c: continue
            if x > a: a, b, c = x, a, b
            elif x > b: b, c = x, b
            elif x > c: c = x
        return c if c > -10**17 else a

