int thirdMax(int* nums, int n) {
    long a=LLONG_MIN,b=LLONG_MIN,c=LLONG_MIN;
    for(int i=0;i<n;i++){
        long x=nums[i];
        if(x==a||x==b||x==c) continue;
        if(x>a){ c=b;b=a;a=x; }
        else if(x>b){ c=b;b=x; }
        else if(x>c) c=x;
    }
    return c>LLONG_MIN/2 ? (int)c : (int)a;
}
